				WHEN RTRIM(CO.CONTR_A) = (SELECT RTRIM(CONTO2) AS COD_CONTR FROM PARA WHERE SUBSTRING(CODICE,1,3) = 'ATT' AND SUBSTRING(CODICE,4,3) = 
					(SELECT TOP 1 RTRIM(LIS_ATTANALCOMBU) FROM IMPIANTI_LI WHERE LIS_CODRAG = (SELECT TOP 1 CCODLIS from IMPIANTI_TE AS TE
						where TE.ID_PMKEY = CO.ID_PMKEY AND TE.ID_RIGO = CO.ID_RIGO AND TE.TIPO_COMPONENTE = CO.TIPO_COMPONENTE ORDER BY id_unique DESC) ORDER BY LIS_DATLIS DESC))
					THEN (SELECT TOP 1 LIS_ANALCOMBU FROM IMPIANTI_LI WHERE LIS_CODRAG = (SELECT TOP 1 CCODLIS from IMPIANTI_TE AS TE where TE.ID_PMKEY = CO.ID_PMKEY AND TE.ID_RIGO = CO.ID_RIGO AND TE.TIPO_COMPONENTE = CO.TIPO_COMPONENTE ORDER BY id_unique DESC) ORDER BY LIS_DATLIS DESC)

				WHEN RTRIM(CO.CONTR_A) = (SELECT RTRIM(CONTO2) AS COD_CONTR FROM PARA WHERE SUBSTRING(CODICE,1,3) = 'ATT' AND SUBSTRING(CODICE,4,3) = 
					(SELECT TOP 1 RTRIM(LIS_ATTREVADC) FROM IMPIANTI_LI WHERE LIS_CODRAG = (SELECT TOP 1 CCODLIS from IMPIANTI_TE AS TE
						where TE.ID_PMKEY = CO.ID_PMKEY AND TE.ID_RIGO = CO.ID_RIGO AND TE.TIPO_COMPONENTE = CO.TIPO_COMPONENTE ORDER BY id_unique DESC) ORDER BY LIS_DATLIS DESC))
					THEN (SELECT TOP 1 LIS_REVADC FROM IMPIANTI_LI WHERE LIS_CODRAG = (SELECT TOP 1 CCODLIS from IMPIANTI_TE AS TE where TE.ID_PMKEY = CO.ID_PMKEY AND TE.ID_RIGO = CO.ID_RIGO AND TE.TIPO_COMPONENTE = CO.TIPO_COMPONENTE ORDER BY id_unique DESC) ORDER BY LIS_DATLIS DESC)

				ELSE CO.CCOSTOA
			END
		),
